/**
 * 鹰眼 · 控辩裁多角色对质引擎（"模拟对质"机制）
 * ------------------------------------------------------------
 * 把医保稽核现场的真实博弈搬进推理：稽核员出疑点(控方) → 医院申诉(辩方) → 专家裁定(裁判)。
 * 申诉Agent本质是"误报过滤器"——这正是"宁漏报不误报"的工程实现。
 *
 * 机制要点（对齐 04_竞品借鉴_多Agent 文档 §2.2）：
 *   1. 只对"高风险L2疑点"和"有合理性争议的线索"启动辩论；L1确定性命中不辩(省成本/防过度生成放大幻觉)。
 *   2. 辩论轮数硬上限=2轮（辩手各陈述+反驳），无果即裁判定夺。
 *   3. 裁判裁决标准=三要素门禁：辩方若指出任一要素缺失或有效反向证据→降级线索/撤销。
 *   4. 辩方反驳理由进入复核界面——服务"可用于对质"承诺。
 *
 * 黑客松阶段：确定性脚本版（演示稳定，按 rule_id 预置控辩裁逻辑）；
 *            LLM 版见 llm-audit.js（单模型多角色 prompt，真辩论）。
 */
'use strict';

// 是否对该 finding 启动辩论：高风险L2疑点 或 争议线索
function shouldDebate(finding, rule) {
  const layer = (rule && rule.layer) || finding.layer || '';
  if (/L1/.test(layer)) return false;               // L1确定性命中不辩
  if (finding.status === '线索') return true;        // 争议线索：展示如何被"辩"成线索
  const highRisk = /高/.test(finding.risk_level || '');
  return highRisk;                                   // 高风险L2疑点才辩
}

// 按 rule_id 预置的辩方论点与裁判裁决（确定性演示版）
